={
  "to": "YOUR_LINE_USER_ID_HERE",
  "messages": [
    {
      "type": "flex",
      "altText": "👑 VIP PURCHASE ALERT",
      "contents": {
        "type": "bubble",
        "size": "kilo",
        "styles": { "header": { "backgroundColor": "#ffaa00" } },
        "header": {
          "type": "box", "layout": "vertical",
          "contents": [{ "type": "text", "text": "👑 VIP PURCHASE ALERT", "color": "#000000", "weight": "bold", "size": "sm" }]
        },
        "body": {
          "type": "box", "layout": "vertical", "spacing": "md",
          "contents": [
            { "type": "text", "text": "✨ ผู้ใช้ VIP สมัครสมาชิก!", "weight": "bold", "size": "md", "wrap": true },
            { "type": "separator", "margin": "md" },
            {
              "type": "box", "layout": "vertical", "spacing": "sm",
              "contents": [
                {
                  "type": "box", "layout": "baseline", "spacing": "sm",
                  "contents": [
                    { "type": "text", "text": "อีเมล", "color": "#aaaaaa", "size": "sm", "flex": 2 },
                    { "type": "text", "text": "{{ $('🔍 Extract Purchase Data').item.json.email }}", "wrap": true, "size": "sm", "color": "#666666", "flex": 5, "weight": "bold" }
                  ]
                },
                {
                  "type": "box", "layout": "baseline", "spacing": "sm",
                  "contents": [
                    { "type": "text", "text": "แพ็กเกจ", "color": "#aaaaaa", "size": "sm", "flex": 2 },
                    { "type": "text", "text": "{{ $('🔍 Extract Purchase Data').item.json.tier }}", "wrap": true, "color": "#666666", "size": "sm", "flex": 5, "weight": "bold" }
                  ]
                },
                {
                  "type": "box", "layout": "baseline", "spacing": "sm",
                  "contents": [
                    { "type": "text", "text": "ยอดเงิน", "color": "#aaaaaa", "size": "sm", "flex": 2 },
                    { "type": "text", "text": "{{ $('🔍 Extract Purchase Data').item.json.amount / 100 }} THB", "wrap": true, "size": "sm", "color": "#ffaa00", "flex": 5, "weight": "bold" }
                  ]
                }
              ]
            },
            { "type": "separator", "margin": "md" },
            { "type": "text", "text": "⚡ ด่วน: ต้อง Remote Setup ให้ลูกค้า!", "size": "sm", "color": "#ff0000", "weight": "bold", "wrap": true }
          ]
        },
        "footer": {
          "type": "box", "layout": "vertical",
          "contents": [{ "type": "text", "text": "ACTION REQUIRED NOW", "size": "xs", "color": "#aaaaaa", "align": "center" }]
        }
      }
    }
  ]
}

